import { prisma } from "@/lib/db";
import { notFound } from "next/navigation";
import Link from 'next/link';
import { ChevronLeft, Package, User } from "lucide-react";

export const dynamic = 'force-dynamic';

export default async function CountryDetailPage({ params }: { params: Promise<{ id: string }> }) {
    const { id } = await params;
    const countryId = parseInt(id);

    if (isNaN(countryId)) notFound();

    const country = await prisma.country.findUnique({
        where: { id: countryId },
        include: {
            brands: {
                include: {
                    products: {
                        where: { countryId: countryId },
                        include: {
                            inventory: true,
                            unit: true,
                            category: true
                        }
                    }
                }
            }
        }
    });

    if (!country) notFound();

    // Filter brands that actually have products from this country (optional, or show all brands that operate there)
    // User requirement: "in country ---> brand ----> final product"
    // We should show brands that have products listed under this country. 
    // BUT user also said "assign many country to brand", so maybe brand operates there but has no products yet?
    // I'll show all brands linked to the country.

    return (
        <div className="space-y-8 animate-in fade-in">
            {/* Header */}
            <div className="flex items-center gap-4">
                <Link href="/admin/inventory/countries" className="p-2 hover:bg-gray-100 rounded-full transition-colors">
                    <ChevronLeft size={24} />
                </Link>
                <div>
                    <h1 className="text-3xl font-bold text-gray-900 flex items-center gap-3">
                        <span className="text-4xl">{/* Flag emoji could go here if we had mapping */}</span>
                        {country.name} ({country.code})
                    </h1>
                    <p className="text-gray-500">Inventory breakdown by Brand for {country.name}.</p>
                </div>
            </div>

            {/* Brands List */}
            <div className="grid gap-6">
                {country.brands.length === 0 ? (
                    <div className="p-12 text-center text-gray-400 bg-gray-50 rounded-2xl border border-gray-100">
                        No brands associated with this country.
                    </div>
                ) : (
                    country.brands.map(brand => {
                        const products = brand.products;
                        const hasProducts = products.length > 0;

                        return (
                            <div key={brand.id} className="card-premium p-6">
                                <div className="flex items-start justify-between mb-4 border-b border-gray-100 pb-4">
                                    <div className="flex items-center gap-3">
                                        <div className="p-2 bg-blue-50 text-blue-600 rounded-lg">
                                            <User size={20} />
                                        </div>
                                        <div>
                                            <h2 className="text-xl font-bold text-gray-900">{brand.name}</h2>
                                            {brand.shortName && <span className="text-sm text-gray-400 font-mono">{brand.shortName}</span>}
                                        </div>
                                    </div>
                                    <span className="text-sm font-medium text-gray-500 bg-gray-100 px-3 py-1 rounded-full">
                                        {products.length} Products in {country.code}
                                    </span>
                                </div>

                                {/* Products Table for this Brand in this Country */}
                                {hasProducts ? (
                                    <div className="overflow-x-auto">
                                        <table className="w-full text-left text-sm">
                                            <thead>
                                                <tr className="text-gray-500 border-b border-gray-100">
                                                    <th className="pb-2 font-medium">Product Name</th>
                                                    <th className="pb-2 font-medium">SKU / Barcode</th>
                                                    <th className="pb-2 font-medium">Size</th>
                                                    <th className="pb-2 font-medium text-right">Stock</th>
                                                </tr>
                                            </thead>
                                            <tbody className="divide-y divide-gray-50">
                                                {products.map(p => {
                                                    const stock = p.inventory.reduce((a, b) => a + Number(b.quantity), 0);
                                                    return (
                                                        <tr key={p.id} className="hover:bg-gray-50/50">
                                                            <td className="py-3 pr-4 font-medium text-gray-900">{p.name}</td>
                                                            <td className="py-3 pr-4 text-gray-500">
                                                                <div className="flex flex-col">
                                                                    <span>{p.sku}</span>
                                                                    <span className="text-[10px]">{p.barcode}</span>
                                                                </div>
                                                            </td>
                                                            <td className="py-3 pr-4 text-gray-600">{Number(p.size)} {p.unit?.shortName}</td>
                                                            <td className="py-3 text-right">
                                                                <span className={`font-bold ${stock > 0 ? 'text-emerald-600' : 'text-red-500'}`}>
                                                                    {stock}
                                                                </span>
                                                            </td>
                                                        </tr>
                                                    );
                                                })}
                                            </tbody>
                                        </table>
                                    </div>
                                ) : (
                                    <div className="text-sm text-gray-400 italic py-2">
                                        No products listed for {country.name} under this brand yet.
                                    </div>
                                )}
                            </div>
                        );
                    })
                )}
            </div>
        </div>
    );
}
